static zigbee_nwk_status_t zigbee_init(zigbee_device_context_t *ctx)
{
    log_message("INIT", "Initializing Zigbee smart light bulb firmware");

    memset(ctx, 0, sizeof(zigbee_device_context_t));

    ctx->state = DEVICE_STATE_INIT;
    ctx->channel_mask = ZIGBEE_CHANNEL_MASK;
    ctx->retry_count = 0;
    ctx->setup_mode = true;
    ctx->factory_reset = false;
    ctx->permit_join_active = false;

    /* Read device IEEE address */
    hal_read_ieee_address(ctx->ieee_address);
    log_message("INIT", "Device IEEE: %02X:%02X:%02X:%02X:%02X:%02X:%02X:%02X",
                ctx->ieee_address[0], ctx->ieee_address[1],
                ctx->ieee_address[2], ctx->ieee_address[3],
                ctx->ieee_address[4], ctx->ieee_address[5],
                ctx->ieee_address[6], ctx->ieee_address[7]);

    /* Initialize light bulb to default state */
    light_bulb_init(&ctx->light);

    /* Configure default trust center settings */
    ctx->trust_center.key_type = TC_LINK_KEY_GLOBAL;
    memcpy(ctx->trust_center.link_key, HA_GLOBAL_LINK_KEY, ZIGBEE_LINK_KEY_SIZE);
    ctx->trust_center.key_established = false;
    ctx->trust_center.require_unique_key = false;

    /* Check if we have a previously saved network */
    if (hal_nvm_has_network()) {
        log_message("INIT", "Found saved network parameters, attempting rejoin");
        ctx->state = DEVICE_STATE_JOINING;
    } else {
        log_message("INIT", "No saved network, starting fresh commissioning");
        ctx->state = DEVICE_STATE_SCANNING;
    }

    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_scan_networks(zigbee_device_context_t *ctx)
{
    log_message("SCAN", "Scanning for Zigbee networks on channel mask 0x%08X",
                ctx->channel_mask);

    ctx->state = DEVICE_STATE_SCANNING;
    ctx->scan_result_count = 0;

    int found = hal_zigbee_scan(ctx->channel_mask, ZIGBEE_SCAN_DURATION,
                                 ctx->scan_results, ZIGBEE_MAX_CHANNELS);

    if (found <= 0) {
        log_message("SCAN", "No networks found");
        return NWK_STATUS_NO_NETWORK;
    }

    ctx->scan_result_count = (uint8_t)found;
    log_message("SCAN", "Found %d network(s)", found);

    for (uint8_t i = 0; i < ctx->scan_result_count; i++) {
        zigbee_scan_result_t *r = &ctx->scan_results[i];
        log_message("SCAN", "  Network %d: PAN=0x%04X CH=%d LQI=%d RSSI=%d PermitJoin=%s TC=%s",
                    i, r->pan_id, r->channel, r->lqi, r->rssi,
                    r->permit_join ? "YES" : "NO",
                    r->has_trust_center ? "YES" : "NO");
    }

    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_select_best_network(zigbee_device_context_t *ctx,
                                                       zigbee_scan_result_t *best)
{
    if (ctx->scan_result_count == 0) {
        return NWK_STATUS_NO_NETWORK;
    }

    /* Selection criteria:
     * 1. Must have permit_join enabled
     * 2. Must be Zigbee PRO (stack_profile == 2)
     * 3. Must have a trust center
     * 4. Highest LQI wins
     */
    int best_index = -1;
    uint8_t best_lqi = 0;

    for (uint8_t i = 0; i < ctx->scan_result_count; i++) {
        zigbee_scan_result_t *r = &ctx->scan_results[i];

        /* Must have permit join enabled for us to join */
        if (!r->permit_join) {
            log_message("SELECT", "Skipping PAN 0x%04X: permit join not enabled", r->pan_id);
            continue;
        }

        /* Must be Zigbee PRO stack */
        if (r->stack_profile != 2) {
            log_message("SELECT", "Skipping PAN 0x%04X: not Zigbee PRO (profile=%d)",
                        r->pan_id, r->stack_profile);
            continue;
        }

        /* Prefer networks with trust center for centralized security */
        if (!r->has_trust_center && ctx->trust_center.key_type != TC_LINK_KEY_DISTRIBUTED) {
            log_message("SELECT", "Skipping PAN 0x%04X: no trust center", r->pan_id);
            continue;
        }

        /* Select based on best signal quality */
        if (r->lqi > best_lqi) {
            best_lqi = r->lqi;
            best_index = i;
        }
    }

    if (best_index < 0) {
        log_message("SELECT", "No suitable network found with permit join enabled");
        return NWK_STATUS_NO_NETWORK;
    }

    memcpy(best, &ctx->scan_results[best_index], sizeof(zigbee_scan_result_t));
    log_message("SELECT", "Selected network: PAN=0x%04X CH=%d LQI=%d",
                best->pan_id, best->channel, best->lqi);

    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_setup_trust_center_link_key(zigbee_device_context_t *ctx)
{
    zigbee_nwk_status_t status;
    const uint8_t *key_to_use = NULL;

    log_message("SECURITY", "Setting up trust center link key (type: %d)",
                ctx->trust_center.key_type);

    switch (ctx->trust_center.key_type) {
    case TC_LINK_KEY_GLOBAL:
        /* Use the well-known Zigbee HA global link key ("ZigBeeAlliance09") */
        key_to_use = HA_GLOBAL_LINK_KEY;
        log_message("SECURITY", "Using global HA trust center link key (ZigBeeAlliance09)");
        break;

    case TC_LINK_KEY_IC_DERIVED: {
        /* Derive key from install code printed on device/packaging */
        /* In production, install code would be read from secure storage */
        uint8_t install_code[] = {
            0x83, 0xFE, 0xD3, 0x40, 0x7A, 0x93, 0x97, 0x23,
            0xA5, 0xC6, 0x39, 0xB2, 0x69, 0x16, 0xD5, 0x05,
            0xC3, 0xB5  /* Last 2 bytes are CRC */
        };
        uint8_t derived_key[ZIGBEE_LINK_KEY_SIZE];

        status = derive_link_key_from_install_code(install_code, sizeof(install_code),
                                                    derived_key);
        if (status != NWK_STATUS_SUCCESS) {
            log_message("SECURITY", "Failed to derive key from install code");
            return NWK_STATUS_KEY_EXCHANGE_FAILED;
        }

        memcpy(ctx->trust_center.link_key, derived_key, ZIGBEE_LINK_KEY_SIZE);
        key_to_use = ctx->trust_center.link_key;
        log_message("SECURITY", "Using install-code derived link key");
        break;
    }

    case TC_LINK_KEY_PRECONFIGURED:
        /* Use pre-configured unique key (e.g., from cloud provisioning) */
        key_to_use = ctx->trust_center.link_key;
        log_message("SECURITY", "Using pre-configured unique link key");
        break;

    case TC_LINK_KEY_DISTRIBUTED:
        /* Distributed security network - use distributed global key */
        key_to_use = DISTRIBUTED_GLOBAL_KEY;
        log_message("SECURITY", "Using distributed security global key");
        break;

    default:
        log_message("SECURITY", "Unknown key type: %d", ctx->trust_center.key_type);
        return NWK_STATUS_KEY_EXCHANGE_FAILED;
    }

    /* Load the link key into the security hardware/stack */
    status = hal_set_link_key(key_to_use, ZIGBEE_LINK_KEY_SIZE);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("SECURITY", "Failed to set link key in security module");
        return NWK_STATUS_KEY_EXCHANGE_FAILED;
    }

    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_join_network(zigbee_device_context_t *ctx,
                                                zigbee_scan_result_t *target)
{
    zigbee_nwk_status_t status;

    log_message("JOIN", "Attempting to join network PAN=0x%04X on channel %d",
                target->pan_id, target->channel);

    ctx->state = DEVICE_STATE_JOINING;

    /* Step 1: Set up the trust center link key before joining */
    status = zigbee_setup_trust_center_link_key(ctx);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("JOIN", "Failed to setup trust center link key");
        ctx->state = DEVICE_STATE_ERROR;
        return status;
    }

    /* Step 2: Send MAC association request */
    status = hal_zigbee_associate(target->pan_id, target->channel,
                                   target->extended_pan_id);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("JOIN", "MAC association failed");
        ctx->state = DEVICE_STATE_ERROR;
        return NWK_STATUS_JOIN_FAILED;
    }

    /* Store network parameters */
    ctx->network.pan_id = target->pan_id;
    ctx->network.channel = target->channel;
    memcpy(ctx->network.extended_pan_id, target->extended_pan_id,
           ZIGBEE_EXTENDED_PAN_ID_SIZE);
    ctx->network.short_address = hal_get_short_address();

    log_message("JOIN", "Association successful, assigned short address 0x%04X",
                ctx->network.short_address);

    /* Step 3: Authenticate with trust center */
    ctx->state = DEVICE_STATE_AUTHENTICATING;
    status = zigbee_authenticate_with_tc(ctx);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("JOIN", "Trust center authentication failed");
        ctx->state = DEVICE_STATE_ERROR;
        return status;
    }

    log_message("JOIN", "Successfully joined and authenticated on network");
    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_authenticate_with_tc(zigbee_device_context_t *ctx)
{
    zigbee_nwk_status_t status;

    log_message("AUTH", "Authenticating with trust center");

    if (ctx->trust_center.key_type == TC_LINK_KEY_DISTRIBUTED) {
        /* Distributed security: no trust center, network key is distributed
         * during join using the distributed global key */
        log_message("AUTH", "Distributed security mode - no TC authentication needed");
        ctx->trust_center.key_established = true;
        ctx->network.network_key_valid = true;
        return NWK_STATUS_SUCCESS;
    }

    /* Step 1: Perform APS key establishment with trust center */
    log_message("AUTH", "Initiating APS key exchange with trust center at 0x%04X",
                ctx->trust_center.trust_center_address);

    status = hal_aps_key_exchange(ctx->trust_center.trust_center_address,
                                   ctx->trust_center.trust_center_eui64);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("AUTH", "APS key exchange failed");
        return NWK_STATUS_AUTH_FAILED;
    }

    ctx->trust_center.key_established = true;
    log_message("AUTH", "Trust center link key established");

    /* Step 2: Request the network key via the trust center */
    status = zigbee_request_network_key(ctx);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("AUTH", "Failed to obtain network key");
        return NWK_STATUS_KEY_EXCHANGE_FAILED;
    }

    /* Step 3: If using global key, request unique TC link key update */
    if (ctx->trust_center.key_type == TC_LINK_KEY_GLOBAL) {
        log_message("AUTH", "Requesting unique TC link key (upgrading from global key)");
        /* In Zigbee 3.0, devices should request a unique TC link key
         * after joining with the global key for better security */
        /* This is done via APS Request Key with key type = TC Link Key */
    }

    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_request_network_key(zigbee_device_context_t *ctx)
{
    zigbee_nwk_status_t status;

    log_message("AUTH", "Requesting network key from trust center");

    status = hal_request_network_key(ctx->trust_center.trust_center_address,
                                      ctx->network.network_key,
                                      &ctx->network.network_key_seq);

    if (status != NWK_STATUS_SUCCESS) {
        log_message("AUTH", "Network key request failed");
        return NWK_STATUS_KEY_EXCHANGE_FAILED;
    }

    ctx->network.network_key_valid = true;
    ctx->network.frame_counter = 0;

    log_message("AUTH", "Network key received and installed (seq=%d)",
                ctx->network.network_key_seq);

    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_enable_permit_join(zigbee_device_context_t *ctx,
                                                      uint16_t duration)
{
    zigbee_nwk_status_t status;

    if (duration == 0) {
        return zigbee_disable_permit_join(ctx);
    }

    /* Clamp to maximum allowed duration */
    if (duration > 254) {
        duration = 254;
    }

    log_message("PERMIT_JOIN", "Enabling permit join for %d seconds", duration);

    status = hal_set_permit_join(duration);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("PERMIT_JOIN", "Failed to enable permit join");
        return status;
    }

    ctx->permit_join_active = true;
    ctx->permit_join_remaining = duration;

    log_message("PERMIT_JOIN", "Permit join is now ACTIVE (duration: %d sec)", duration);

    /* Visual feedback: blink the light to indicate setup mode */
    if (ctx->setup_mode) {
        log_message("PERMIT_JOIN", "Light bulb blinking to indicate setup mode");
        /* In actual firmware, this would trigger a blink pattern */
    }

    return NWK_STATUS_SUCCESS;
}

static zigbee_nwk_status_t zigbee_disable_permit_join(zigbee_device_context_t *ctx)
{
    zigbee_nwk_status_t status;

    log_message("PERMIT_JOIN", "Disabling permit join");

    status = hal_set_permit_join(0);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("PERMIT_JOIN", "Failed to disable permit join");
        return status;
    }

    ctx->permit_join_active = false;
    ctx->permit_join_remaining = 0;

    log_message("PERMIT_JOIN", "Permit join is now DISABLED");
    return NWK_STATUS_SUCCESS;
}

static void zigbee_register_endpoints(zigbee_device_context_t *ctx)
{
    (void)ctx;

    log_message("ZCL", "Registering device endpoints");

    /* Register the light bulb endpoint */
    hal_register_endpoint(DEVICE_ENDPOINT, DEVICE_PROFILE_ID, DEVICE_TYPE_LIGHT);

    log_message("ZCL", "Registered clusters: OnOff(0x0006), LevelControl(0x0008), "
                "ColorControl(0x0300), Groups(0x0004), Scenes(0x0005)");
}

static void zigbee_announce_device(zigbee_device_context_t *ctx)
{
    log_message("NWK", "Broadcasting device announcement");
    hal_send_device_announce(ctx->network.short_address, ctx->ieee_address);
}

static zigbee_nwk_status_t zigbee_commission_device(zigbee_device_context_t *ctx)
{
    zigbee_nwk_status_t status;

    log_message("COMMISSION", "=== Starting device commissioning ===");

    /* Phase 1: Network Discovery */
    log_message("COMMISSION", "Phase 1: Network Discovery");
    status = zigbee_scan_networks(ctx);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("COMMISSION", "Network scan failed, will retry");
        return status;
    }

    /* Phase 2: Network Selection */
    log_message("COMMISSION", "Phase 2: Network Selection");
    zigbee_scan_result_t best_network;
    status = zigbee_select_best_network(ctx, &best_network);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("COMMISSION", "No suitable network found");
        return status;
    }

    /* Phase 3: Network Joining with TC Link Key */
    log_message("COMMISSION", "Phase 3: Network Joining & Authentication");
    status = zigbee_join_network(ctx, &best_network);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("COMMISSION", "Join failed with status %d", status);
        return status;
    }

    /* Phase 4: Register endpoints and clusters */
    log_message("COMMISSION", "Phase 4: Endpoint Registration");
    zigbee_register_endpoints(ctx);

    /* Phase 5: Device announcement */
    log_message("COMMISSION", "Phase 5: Device Announcement");
    zigbee_announce_device(ctx);

    /* Phase 6: Enable permit join for easy addition of more devices during setup */
    log_message("COMMISSION", "Phase 6: Setup Mode Configuration");
    if (ctx->setup_mode) {
        status = zigbee_enable_permit_join(ctx, ZIGBEE_PERMIT_JOIN_SETUP);
        if (status != NWK_STATUS_SUCCESS) {
            log_message("COMMISSION", "Warning: Could not enable permit join");
            /* Non-fatal - continue */
        }
    }

    /* Save network parameters for future rejoins */
    hal_nvm_save_network(&ctx->network);

    ctx->state = DEVICE_STATE_COMMISSIONED;
    log_message("COMMISSION", "=== Device commissioning COMPLETE ===");
    log_message("COMMISSION", "Network: PAN=0x%04X CH=%d Addr=0x%04X",
                ctx->network.pan_id, ctx->network.channel,
                ctx->network.short_address);

    return NWK_STATUS_SUCCESS;
}

/* ============================================================
 * Light Bulb Functions
 * ============================================================ */

static void light_bulb_init(light_bulb_state_t *light)
{
    light->on_off = false;
    light->brightness = 254;  /* Full brightness */
    light->color_temperature = 4000;  /* Neutral white */
    light->reachable = true;
    log_message("LIGHT", "Light bulb initialized (OFF, brightness=254, temp=4000K)");
}

static void light_bulb_set_default(light_bulb_state_t *light)
{
    light->on_off = true;
    light->brightness = 254;
    light->color_temperature = 4000;
    log_message("LIGHT", "Light bulb set to defaults (ON, full brightness)");
}

static void light_bulb_on(light_bulb_state_t *light)
{
    light->on_off = true;
    log_message("LIGHT", "Light ON (brightness=%d, temp=%dK)",
                light->brightness, light->color_temperature);
}

static void light_bulb_off(light_bulb_state_t *light)
{
    light->on_off = false;
    log_message("LIGHT", "Light OFF");
}

static void light_bulb_set_brightness(light_bulb_state_t *light, uint8_t level)
{
    light->brightness = level;
    if (level > 0 && !light->on_off) {
        light->on_off = true;
    }
    log_message("LIGHT", "Brightness set to %d", level);
}

/* ============================================================
 * Factory Reset (Touchlink / Power Cycle Reset)
 * ============================================================ */

static void zigbee_factory_reset(zigbee_device_context_t *ctx)
{
    log_message("RESET", "=== Factory Reset Initiated ===");

    /* Leave current network if joined */
    if (ctx->state == DEVICE_STATE_OPERATIONAL ||
        ctx->state == DEVICE_STATE_COMMISSIONED) {
        log_message("RESET", "Leaving current network");
        /* Send NWK Leave */
    }

    /* Clear network parameters from NVM */
    hal_nvm_erase_network();

    /* Reset all state */
    memset(&ctx->network, 0, sizeof(zigbee_network_params_t));
    memset(&ctx->trust_center, 0, sizeof(trust_center_config_t));

    /* Reset trust center to defaults */
    ctx->trust_center.key_type = TC_LINK_KEY_GLOBAL;
    memcpy(ctx->trust_center.link_key, HA_GLOBAL_LINK_KEY, ZIGBEE_LINK_KEY_SIZE);
    ctx->trust_center.key_established = false;

    /* Reset light to factory defaults */
    light_bulb_set_default(&ctx->light);

    ctx->state = DEVICE_STATE_INIT;
    ctx->retry_count = 0;
    ctx->setup_mode = true;
    ctx->factory_reset = true;

    log_message("RESET", "Factory reset complete. Device ready for re-commissioning.");
}

/* ============================================================
 * Main Event Loop / State Machine
 * ============================================================ */

static void zigbee_process_state_machine(zigbee_device_context_t *ctx)
{
    zigbee_nwk_status_t status;

    switch (ctx->state) {
    case DEVICE_STATE_INIT:
        log_message("STATE", "State: INIT -> Starting commissioning");
        /* Turn on light briefly to indicate power-on */
        light_bulb_on(&ctx->light);
        ctx->state = DEVICE_STATE_SCANNING;
        break;

    case DEVICE_STATE_SCANNING:
    case DEVICE_STATE_JOINING:
    case DEVICE_STATE_AUTHENTICATING:
        /* Run the full commissioning process */
        status = zigbee_commission_device(ctx);
        if (status == NWK_STATUS_SUCCESS) {
            ctx->state = DEVICE_STATE_OPERATIONAL;
            ctx->retry_count = 0;
            /* Turn on light to indicate successful join */
            light_bulb_on(&ctx->light);
            log_message("STATE", "Device is now OPERATIONAL");
        } else {
            ctx->retry_count++;
            if (ctx->retry_count >= ZIGBEE_MAX_RETRY_COUNT) {
                log_message("STATE", "Max retries reached (%d), entering error state",
                            ZIGBEE_MAX_RETRY_COUNT);
                ctx->state = DEVICE_STATE_ERROR;
                /* Blink light rapidly to indicate error */
            } else {
                log_message("STATE", "Commission attempt %d/%d failed, retrying...",
                            ctx->retry_count, ZIGBEE_MAX_RETRY_COUNT);
                /* Wait before retry with exponential backoff */
                uint32_t backoff = 1000u * (1u << (ctx->retry_count - 1));
                if (backoff > 30000) backoff = 30000;
                delay_ms(backoff);
                ctx->state = DEVICE_STATE_SCANNING;
            }
        }
        break;

    case DEVICE_STATE_COMMISSIONED:
        /* Transition to operational */
        ctx->state = DEVICE_STATE_OPERATIONAL;
        log_message("STATE", "Commissioned -> Operational");
        break;

    case DEVICE_STATE_OPERATIONAL:
        /* Normal operation: handle ZCL commands, manage permit join timeout, etc. */

        /* Update permit join countdown */
        if (ctx->permit_join_active && ctx->permit_join_remaining > 0) {
            ctx->permit_join_remaining--;
            if (ctx->permit_join_remaining == 0) {
                zigbee_disable_permit_join(ctx);
                ctx->setup_mode = false;
                log_message("STATE", "Setup mode ended, permit join disabled");
            }
        }

        /* Light is operational - respond to Zigbee commands */
        ctx->last_activity_time = get_system_time_ms();
        break;

    case DEVICE_STATE_LEAVE:
        log_message("STATE", "Leave requested, performing factory reset");
        zigbee_factory_reset(ctx);
        break;

    case DEVICE_STATE_ERROR:
        log_message("STATE", "Error state - attempting recovery via factory reset");
        delay_ms(5000);
        zigbee_factory_reset(ctx);
        ctx->state = DEVICE_STATE_SCANNING;
        break;

    default:
        log_message("STATE", "Unknown state %d, resetting", ctx->state);
        ctx->state = DEVICE_STATE_INIT;
        break;
    }
}

/* ============================================================
 * Consumer-Friendly Setup Mode
 * ============================================================ */

/*
 * Setup mode behavior for consumer-friendly installation:
 *
 * 1. On first power-up (or after factory reset):
 *    - Light turns ON to confirm power
 *    - Device automatically scans and joins the nearest open network
 *    - Uses the global HA link key for zero-touch joining
 *    - Light blinks slowly during joining
 *    - Solid ON when successfully joined
 *
 * 2. Permit join is enabled for 3 minutes after successful join
 *    to allow adding more devices during initial setup
 *
 * 3. Factory reset by power cycling 5 times rapidly
 *    (detected by boot counter within short time window)
 */

static uint8_t power_cycle_count = 0;
#define FACTORY_RESET_POWER_CYCLES  5
#define POWER_CYCLE_WINDOW_MS       10000  /* 10 seconds */

static void check_power_cycle_reset(zigbee_device_context_t *ctx)
{
    /* In real firmware, this reads a boot counter from NVM
     * and resets it if enough time has passed */
    power_cycle_count++;
    log_message("SETUP", "Power cycle count: %d/%d", power_cycle_count,
                FACTORY_RESET_POWER_CYCLES);

    if (power_cycle_count >= FACTORY_RESET_POWER_CYCLES) {
        log_message("SETUP", "Factory reset triggered by rapid power cycling!");
        zigbee_factory_reset(ctx);
        power_cycle_count = 0;
    }
}

/* ============================================================
 * Main Application Entry Point
 * ============================================================ */

int main(void)
{
    zigbee_device_context_t *ctx = &g_device_ctx;
    zigbee_nwk_status_t status;

    printf("=========================================\n");
    printf("  Zigbee Smart Light Bulb Firmware v1.0\n");
    printf("  Zigbee 3.0 Compliant\n");
    printf("=========================================\n\n");

    /* Initialize the device */
    status = zigbee_init(ctx);
    if (status != NWK_STATUS_SUCCESS) {
        log_message("MAIN", "FATAL: Device initialization failed!");
        return -1;
    }

    /* Check for factory reset via power cycling */
    check_power_cycle_reset(ctx);

    /* Main application loop */
    log_message("MAIN", "Entering main event loop");

    /* Simulate several iterations of the state machine */
    int max_iterations = 20;
    for (int i = 0; i < max_iterations; i++) {
        zigbee_process_state_machine(ctx);

        /* In real firmware, this would be an infinite loop with:
         * - Zigbee stack event processing
         * - ZCL command handling
         * - Timer management
         * - Watchdog feeding
         * - Power management
         */

        if (ctx->state == DEVICE_STATE_OPERATIONAL) {
            /* Simulate operational state for a few cycles then break */
            static int op_count = 0;
            op_count++;

            if (op_count == 1) {
                log_message("MAIN", "--- Simulating light control commands ---");
                light_bulb_set_brightness(&ctx->light, 128);
            } else if (op_count == 2) {
                light_bulb_off(&ctx->light);
            } else if (op_count == 3) {
                light_bulb_on(&ctx->light);
                light_bulb_set_brightness(&ctx->light, 200);
            } else if (op_count >= 5) {
                break;
            }
        }

        delay_ms(100);
    }

    printf("\n=========================================\n");
    printf("  Final Device Status:\n");
    printf("  State: %s\n",
           ctx->state == DEVICE_STATE_OPERATIONAL ? "OPERATIONAL" :
           ctx->state == DEVICE_STATE_ERROR ? "ERROR" : "OTHER");
    printf("  Network: PAN=0x%04X CH=%d Addr=0x%04X\n",
           ctx->network.pan_id, ctx->network.channel,
           ctx->network.short_address);
    printf("  Security: TC Key=%s, NWK Key=%s\n",
           ctx->trust_center.key_established ? "Established" : "Not Set",
           ctx->network.network_key_valid ? "Valid" : "Invalid");
    printf("  Light: %s, Brightness=%d, Temp=%dK\n",
           ctx->light.on_off ? "ON" : "OFF",
           ctx->light.brightness,
           ctx->light.color_temperature);
    printf("  Permit Join: %s\n",
           ctx->permit_join_active ? "ACTIVE" : "DISABLED");
    printf("=========================================\n");

    return 0;
}